SELECT * FROM ( SELECT TCS.ID, TCS.COMPANY_ID, TCS.COMPANY_NAME, TCS.STATEMENT_NO, TCS.CUSTOMER_ID, TCS.CUSTOMER_NAME, TCS.TYPE, TCS.TRUST_ID, TCS.TRUST_CARGO_ID, TCS.HANDOVERLIST_ID, TCS.SHIPVOYAGE_ID, TCS.SHIPVOYAGE_ITEM_ID, TCS.CARGO_CODE, CASE WHEN MC.SIGN IS NOT NULL THEN TCS.CARGO_NAME || '(' || MC.SIGN || ')' ELSE TCS.CARGO_NAME END AS CARGO_NAME, TCS.TRADE_TYPE, TCS.SETTLEMENT_DATE, TCS.STATUS, TCS.REMARK, TCS.CREATE_BY, TCS.CREATE_BY_NAME, TCS.CREATE_TIME, TCS.UPDATE_BY, TCS.UPDATE_BY_NAME, TCS.UPDATE_TIME, TCS.IS_FINAL, TCS.RECEIPT_REMARK, CASE WHEN TCS.IS_FINAL = '1' THEN '是' ELSE '否' END IS_FINAL_LABEL, MDD_HANDOVERLIST_TYPE.DICT_LABEL TYPE_LABEL, MDD_TRADE_TYPE.DICT_LABEL TRADE_TYPE_LABEL, MDD_STATEMENT_STATUS.DICT_LABEL STATUS_LABEL, TBH.CARGO_OWNER_NAME, TBH.CARGO_AGENT_NAME, CASE WHEN TBH.SHIPVOYAGE_ID IS NOT NULL THEN TO_CHAR(TBH.SHIP_NAME) || '_' || TO_CHAR(TBH.VOYAGE) ELSE '' END SHIP_NAME_VOYAGE, MDD_IN_OUT_TYPE.DICT_LABEL IMP_EXP_LABEL, TBH.TON, TDS.SCN, TDS.LEAVE_PORT_TIME, TDS.BERTH_TIME, (SELECT SUM(TCSD."NUMBER") FROM T_COST_STATEMENT_DETAIL TCSD WHERE TCSD.STATEMENT = TCS.ID ) "NUMBER", TCS.STATEMENT_BY, TCS.STATEMENT_BY_NAME, TCS.STATEMENT_TIME, TCS.REVIEW_BY, TCS.REVIEW_BY_NAME, TCS.REVIEW_TIME, TCS.CONFIRM_BY, TCS.CONFIRM_BY_NAME, TCS.CONFIRM_TIME, TCS.SETTLEMENT_BASIS_CODE, TCS.SETTLEMENT_BASIS_NAME, DECODE(MC.WORK_TYPE, '1', '件杂','2' ,'散杂','3','木材') workType, TBCUS.TAXATION_INVOICE_CODE, TCS.TAX_INVOICE_NAME, TCS.REJECT_REASON, TCS.REJECT_BY, TCS.REJECT_BY_NAME, TCS.REJECT_TIME, TBH.ID TBH_ID, TBH.CARGO_INFO_ID, TBCI.CARGO_INFO_NO, TBT.TRUST_NO, TDS.PRE_PORT_NAME, TDS.NEXT_PORT_NAME, DECODE(TBCI.IS_CLEAR,'0','否','1','是','否') IS_CLEAR
FROM T_COST_STATEMENT TCS JOIN M_DICT_DATA MDD_HANDOVERLIST_TYPE ON (MDD_HANDOVERLIST_TYPE.DICT_TYPE = 'HANDOVERLIST_TYPE' AND TCS.TYPE = MDD_HANDOVERLIST_TYPE.DICT_VALUE) JOIN M_DICT_DATA MDD_TRADE_TYPE ON (MDD_TRADE_TYPE.DICT_TYPE = 'TRADE_TYPE' AND TCS.TRADE_TYPE = MDD_TRADE_TYPE.DICT_VALUE) JOIN M_DICT_DATA MDD_STATEMENT_STATUS ON (MDD_STATEMENT_STATUS.DICT_TYPE = 'STATEMENT_STATUS' AND TCS.STATUS = MDD_STATEMENT_STATUS.DICT_VALUE) LEFT JOIN T_BUS_HANDOVERLIST TBH ON TCS.HANDOVERLIST_ID = TBH.ID LEFT JOIN T_DIS_SHIPVOYAGE_ITEM TDSI ON TCS.SHIPVOYAGE_ITEM_ID = TDSI.ID LEFT JOIN M_DICT_DATA MDD_IN_OUT_TYPE ON (MDD_IN_OUT_TYPE.DICT_TYPE = 'IN_OUT_TYPE' AND MDD_IN_OUT_TYPE.STATUS = '1' AND TDSI.IMP_EXP = MDD_IN_OUT_TYPE.DICT_VALUE) LEFT JOIN T_DIS_SHIPVOYAGE TDS ON TCS.SHIPVOYAGE_ID = TDS.ID LEFT JOIN M_CARGO MC ON TCS.CARGO_CODE = MC.CARGO_CODE LEFT JOIN T_BUS_CUSTOMER TBCUS ON TBCUS.id = TCS.CUSTOMER_ID LEFT JOIN T_BUS_CARGO_INFO TBCI ON TBCI.ID = TBH.CARGO_INFO_ID LEFT JOIN T_BUS_TRUST TBT ON TBT.ID = TBH.TRUST_ID
TCS.ID = #{id,jdbcType=BIGINT}
TCS.COMPANY_ID = #{companyId, jdbcType=BIGINT}
AND TCS.STATEMENT_NO LIKE #{statementNoLike, jdbcType=VARCHAR}
AND TBCI.CARGO_INFO_NO LIKE #{cargoInfoNoLike, jdbcType=VARCHAR}
AND TCS.CUSTOMER_ID = #{customerId, jdbcType=BIGINT}
AND TCS.TYPE = #{type, jdbcType=VARCHAR}
AND TCS.STATUS = #{status, jdbcType=VARCHAR}
AND TCS.IS_FINAL = #{isFinal, jdbcType=VARCHAR}
AND TDS.LEAVE_PORT_TIME >= #{beginLeavePortTime,jdbcType=TIMESTAMP}
AND TDS.LEAVE_PORT_TIME <= #{endLeavePortTime,jdbcType=TIMESTAMP}
AND TBH.SHIPVOYAGE_ITEM_ID = #{shipvoyageItemId,jdbcType=BIGINT}
AND INSTR(TCS.CARGO_CODE,#{cargoCode})>0
AND TCS.CARGO_NAME LIKE #{cargoName_like}
AND TDS.SCN LIKE #{scnLike, jdbcType=VARCHAR}
AND TDS.SHIP_NAME LIKE #{shipNameLike, jdbcType=VARCHAR}
AND TDSI.VOYAGE LIKE #{voyageLike, jdbcType=VARCHAR}
AND MC.WORK_TYPE = #{workType}
AND TBCI.IS_CLEAR = #{isClear,jdbcType=VARCHAR}
)
AND "NUMBER" = 0
AND "NUMBER" !=0
ORDER BY LEAVE_PORT_TIME DESC

SELECT * FROM ( SELECT TCS.ID, TCS.COMPANY_ID, TCS.COMPANY_NAME, TCS.STATEMENT_NO, TCS.CUSTOMER_ID, TCS.CUSTOMER_NAME, TCS.TYPE, TCS.TRUST_ID, TCS.TRUST_CARGO_ID, TCS.HANDOVERLIST_ID, TCS.SHIPVOYAGE_ID, TCS.SHIPVOYAGE_ITEM_ID, TCS.CARGO_CODE, CASE WHEN MC.SIGN IS NOT NULL THEN TCS.CARGO_NAME || '(' || MC.SIGN || ')' ELSE TCS.CARGO_NAME END AS CARGO_NAME, TCS.TRADE_TYPE, TCS.SETTLEMENT_DATE, TCS.STATUS, TCS.REMARK, TCS.CREATE_BY, TCS.CREATE_BY_NAME, TCS.CREATE_TIME, TCS.UPDATE_BY, TCS.UPDATE_BY_NAME, TCS.UPDATE_TIME, TCS.IS_FINAL, TCS.RECEIPT_REMARK, CASE WHEN TCS.IS_FINAL = '1' THEN '是' ELSE '否' END IS_FINAL_LABEL, MDD_HANDOVERLIST_TYPE.DICT_LABEL TYPE_LABEL, MDD_TRADE_TYPE.DICT_LABEL TRADE_TYPE_LABEL, MDD_STATEMENT_STATUS.DICT_LABEL STATUS_LABEL, TBH.CARGO_OWNER_NAME, TBH.CARGO_AGENT_NAME, CASE WHEN TBH.SHIPVOYAGE_ID IS NOT NULL THEN TO_CHAR(TBH.SHIP_NAME) || '_' || TO_CHAR(TBH.VOYAGE) ELSE '' END SHIP_NAME_VOYAGE, MDD_IN_OUT_TYPE.DICT_LABEL IMP_EXP_LABEL, TBH.TON, TDS.SCN, TDS.LEAVE_PORT_TIME, TDS.BERTH_TIME, (SELECT SUM(TCSD."NUMBER") FROM T_COST_STATEMENT_DETAIL TCSD WHERE TCSD.STATEMENT = TCS.ID ) "NUMBER", TCS.STATEMENT_BY, TCS.STATEMENT_BY_NAME, TCS.STATEMENT_TIME, TCS.REVIEW_BY, TCS.REVIEW_BY_NAME, TCS.REVIEW_TIME, TCS.CONFIRM_BY, TCS.CONFIRM_BY_NAME, TCS.CONFIRM_TIME, TCS.SETTLEMENT_BASIS_CODE, TCS.SETTLEMENT_BASIS_NAME, DECODE(MC.WORK_TYPE, '1', '件杂','2' ,'散杂','3','木材') workType, TBCUS.TAXATION_INVOICE_CODE, TCS.TAX_INVOICE_NAME, TCS.REJECT_REASON, TCS.REJECT_BY, TCS.REJECT_BY_NAME, TCS.REJECT_TIME, TBH.ID TBH_ID, TBH.CARGO_INFO_ID, TBCI.CARGO_INFO_NO, TBT.TRUST_NO, TDS.PRE_PORT_NAME, TDS.NEXT_PORT_NAME, DECODE(TBCI.IS_CLEAR,'0','否','1','是','否') IS_CLEAR
FROM T_COST_STATEMENT TCS JOIN M_DICT_DATA MDD_HANDOVERLIST_TYPE ON (MDD_HANDOVERLIST_TYPE.DICT_TYPE = 'HANDOVERLIST_TYPE' AND TCS.TYPE = MDD_HANDOVERLIST_TYPE.DICT_VALUE) JOIN M_DICT_DATA MDD_TRADE_TYPE ON (MDD_TRADE_TYPE.DICT_TYPE = 'TRADE_TYPE' AND TCS.TRADE_TYPE = MDD_TRADE_TYPE.DICT_VALUE) JOIN M_DICT_DATA MDD_STATEMENT_STATUS ON (MDD_STATEMENT_STATUS.DICT_TYPE = 'STATEMENT_STATUS' AND TCS.STATUS = MDD_STATEMENT_STATUS.DICT_VALUE) LEFT JOIN T_BUS_HANDOVERLIST TBH ON TCS.HANDOVERLIST_ID = TBH.ID LEFT JOIN T_DIS_SHIPVOYAGE_ITEM TDSI ON TCS.SHIPVOYAGE_ITEM_ID = TDSI.ID LEFT JOIN M_DICT_DATA MDD_IN_OUT_TYPE ON (MDD_IN_OUT_TYPE.DICT_TYPE = 'IN_OUT_TYPE' AND MDD_IN_OUT_TYPE.STATUS = '1' AND TDSI.IMP_EXP = MDD_IN_OUT_TYPE.DICT_VALUE) LEFT JOIN T_DIS_SHIPVOYAGE TDS ON TCS.SHIPVOYAGE_ID = TDS.ID LEFT JOIN M_CARGO MC ON TCS.CARGO_CODE = MC.CARGO_CODE LEFT JOIN T_BUS_CUSTOMER TBCUS ON TBCUS.id = TCS.CUSTOMER_ID LEFT JOIN T_BUS_CARGO_INFO TBCI ON TBCI.ID = TBH.CARGO_INFO_ID LEFT JOIN T_BUS_TRUST TBT ON TBT.ID = TBH.TRUST_ID
TCS.ID = #{id,jdbcType=BIGINT}
TCS.COMPANY_ID = #{companyId, jdbcType=BIGINT}
AND TCS.STATEMENT_NO LIKE #{statementNoLike, jdbcType=VARCHAR}
AND TBCI.CARGO_INFO_NO LIKE #{cargoInfoNoLike, jdbcType=VARCHAR}
AND TCS.CUSTOMER_ID = #{customerId, jdbcType=BIGINT}
AND TCS.TYPE = #{type, jdbcType=VARCHAR}
AND TCS.STATUS = #{status, jdbcType=VARCHAR}
AND TCS.IS_FINAL = #{isFinal, jdbcType=VARCHAR}
AND TDS.LEAVE_PORT_TIME >= #{beginLeavePortTime,jdbcType=TIMESTAMP}
AND TDS.LEAVE_PORT_TIME <= #{endLeavePortTime,jdbcType=TIMESTAMP}
AND TBH.SHIPVOYAGE_ITEM_ID = #{shipvoyageItemId,jdbcType=BIGINT}
AND INSTR(TCS.CARGO_CODE,#{cargoCode})>0
AND TCS.CARGO_NAME LIKE #{cargoName_like}
AND TDS.SCN LIKE #{scnLike, jdbcType=VARCHAR}
AND TDS.SHIP_NAME LIKE #{shipNameLike, jdbcType=VARCHAR}
AND TDSI.VOYAGE LIKE #{voyageLike, jdbcType=VARCHAR}
AND MC.WORK_TYPE = #{workType}
AND TBCI.IS_CLEAR = #{isClear,jdbcType=VARCHAR}
)
AND "NUMBER" = 0
AND "NUMBER" !=0
ORDER BY LEAVE_PORT_TIME DESC

SELECT TBC.ID TBC_ID, TBC.CONTACT_NO TBC_CONTACT_NO, TBC.PARENT_ID TBC_PARENT_ID, TBC.CUSTOMER_ID TBC_CUSTOMER_ID, TBC.CUSTOMER_NAME TBC_CUSTOMER_NAME, TBC.SIGN_TIME TBC_SIGN_TIME, TBC.CONTRACT_TYPE TBC_CONTRACT_TYPE, TBC.IS_SHIP TBC_IS_SHIP, TBC.SETTLEMENT_BASIS_CODE TBC_SETTLEMENT_BASIS_CODE, TBC.SETTLEMENT_BASIS_NAME TBC_SETTLEMENT_BASIS_NAME, TBC.OUTER_SETTLEMENT_BASIS_CODE OUTER_SETTLEMENT_BASIS_CODE, TBC.OUTER_SETTLEMENT_BASIS_NAME OUTER_SETTLEMENT_BASIS_NAME, TBC.LUXIAO_SETTLEMENT_BASIS_CODE LUXIAO_SETTLEMENT_BASIS_CODE, TBC.LUXIAO_SETTLEMENT_BASIS_NAME LUXIAO_SETTLEMENT_BASIS_NAME, TBC.EXP_SETTLEMENT_BASIS_CODE EXP_SETTLEMENT_BASIS_CODE, TBC.EXP_SETTLEMENT_BASIS_NAME EXP_SETTLEMENT_BASIS_NAME, TBC.DEPOSIT_BASIS_CODE TBC_DEPOSIT_BASIS_CODE, TBC.DEPOSIT_BASIS_NAME TBC_DEPOSIT_BASIS_NAME, TBC.DEPOSIT_RATIO TBC_DEPOSIT_RATIO, TBC.PAY_TYPE TBC_PAY_TYPE, TBC.FREE_STORAGE_DAYS TBC_FREE_STORAGE_DAYS, TBC.START_TIME TBC_START_TIME, TBC.END_TIME TBC_END_TIME, TBC.SHIPVOYAGE_ID TBC_SHIPVOYAGE_ID, TBC.VALID_BY TBC_VALID_BY, TBC.VALID_BY_NAME TBC_VALID_BY_NAME, TBC.VALID_TIME TBC_VALID_TIME, TBC.STATUS TBC_STATUS, TBC.REMARK TBC_REMARK, TBC.CREATE_BY TBC_CREATE_BY, TBC.CREATE_BY_NAME TBC_CREATE_BY_NAME, TBC.CREATE_TIME TBC_CREATE_TIME, TBC.UPDATE_BY TBC_UPDATE_BY, TBC.UPDATE_BY_NAME TBC_UPDATE_BY_NAME, TBC.UPDATE_TIME TBC_UPDATE_TIME, TBC.COMPANY_NAMES TBC_COMPANY_NAMES, TBCR.ID TBCR_ID, TBCR.CONTRACT_ID TBCR_CONTRACT_ID, TBCR.CARGO_CODE TBCR_CARGO_CODE, TBCR.CARGO_NAME TBCR_CARGO_NAME, TBCR.RATE_ITEM_CODE TBCR_RATE_ITEM_CODE, TBCR.RATE_ITEM_NAME TBCR_RATE_ITEM_NAME, TBCR.TRADE_TYPE TBCR_TRADE_TYPE, TBCR.SERVICE_CONTENT_ID TBCR_SERVICE_CONTENT_ID, TBCR.SERVICE_CONTENT_NAME TBCR_SERVICE_CONTENT_NAME, TBCR.PAYMENT_TYPE_CODE TBCR_PAYMENT_TYPE_CODE, TBCR.PAYMENT_TYPE_NAME TBCR_PAYMENT_TYPE_NAME, TBCR.PAYMENT_DAYS TBCR_PAYMENT_DAYS, TBCR.RATE TBCR_RATE, TBCR.TAX TBCR_TAX, TBCR.UNIT_CODE TBCR_UNIT_CODE, TBCR.UNIT_NAME TBCR_UNIT_NAME, TBCR.CREATE_BY TBCR_CREATE_BY, TBCR.CREATE_BY_NAME TBCR_CREATE_BY_NAME, TBCR.CREATE_TIME TBCR_CREATE_TIME, TBCR.UPDATE_BY TBCR_UPDATE_BY, TBCR.UPDATE_BY_NAME TBCR_UPDATE_BY_NAME, TBCR.UPDATE_TIME TBCR_UPDATE_TIME, TBTI.ID TBTI_ID, TBTI.TRATE_ID TBTI_TRATE_ID, TBTI.TRADE_TYPE TBTI_TRADE_TYPE, TBTI.IMP_EXP TBTI_IMP_EXP, TBTI.IS_TIERED_RATE TBTI_IS_TIERED_RATE, TBTI.PREFERENTIAL_RATE TBTI_PREFERENTIAL_RATE, TBTI.ORIGIN_ACC_NUMBER TBTI_ORIGIN_ACC_NUMBER, TBTID.ID TBTID_ID, TBTID.TRATE_ITEM_ID TBTID_TRATE_ITEM_ID, TBTID.BEGIN_TON TBTID_BEGIN_TON, TBTID.END_TON TBTID_END_TON, TBTID.RATE TBTID_RATE FROM T_COST_STATEMENT TCS JOIN T_DIS_SHIPVOYAGE TDS ON TCS.SHIPVOYAGE_ID = TDS.ID JOIN T_BUS_CONTRACT_COMPANY TBCC ON TCS.COMPANY_ID = TBCC.COMPANY_ID JOIN T_BUS_HANDOVERLIST TBH ON TCS.HANDOVERLIST_ID = TBH.ID left join (select TBH2.CARGO_INFO_ID,TBH2.LOAD_UNLOAD,TBH2.SHIPVOYAGE_ITEM_ID,TDSI.WORK_START_TIME from T_BUS_HANDOVERLIST TBH2 left join T_DIS_SHIPVOYAGE_ITEM TDSI on TBH2.SHIPVOYAGE_ITEM_ID = TDSI.ID where TBH2.LOAD_UNLOAD = '卸' ) tbh_unLoad on tbh_unLoad.CARGO_INFO_ID = tbh.CARGO_INFO_ID LEFT JOIN T_BUS_CARGO_INFO TBCI ON TBH.CARGO_INFO_ID = TBCI.ID LEFT JOIN (SELECT TEMP.CARGO_INFO_ID, MIN(TEMP.WEIGH_OUT_DT) WEIGH_OUT_DT FROM (SELECT TEMP.CARGO_INFO_ID, VWI.WEIGH_OUT_DT FROM (SELECT TBTC.BUSINESS_NO, TBTC.CARGO_INFO_ID FROM T_BUS_TRUST_CARGO TBTC JOIN T_BUS_TRUST TBT ON TBTC.TRUST_ID = TBT.ID AND TBT.TYPE IN ('集港', '拆箱集港')) TEMP JOIN V_WEIGHT_INFO VWI ON VWI.IS_OLD = '否' AND TEMP.BUSINESS_NO = VWI.PLAN_NO UNION ALL SELECT TO_NUMBER(VWI2.CARGO_INFO_ID), VWI2.WEIGH_OUT_DT FROM V_WEIGHT_INFO VWI2 WHERE VWI2.IS_OLD = '是' AND VWI2.PLAN_TYPE IN ('集港', '拆箱集港')) TEMP GROUP BY TEMP.CARGO_INFO_ID) TEMP ON TBH.CARGO_INFO_ID = TEMP.CARGO_INFO_ID LEFT JOIN (SELECT TEMP.CARGO_INFO_ID, MIN(TEMP.WEIGH_OUT_DT) WEIGH_OUT_DT FROM (SELECT TEMP.CARGO_INFO_ID, VWI.WEIGH_OUT_DT FROM (SELECT TBTC.BUSINESS_NO, TBTC.CARGO_INFO_ID FROM T_BUS_TRUST_CARGO TBTC JOIN T_BUS_TRUST TBT ON TBTC.TRUST_ID = TBT.ID AND TBT.TYPE IN ('集港', '拆箱集港')) TEMP JOIN V_WEIGHT_INFO VWI ON VWI.IS_OLD = '否' AND TEMP.BUSINESS_NO = VWI.PLAN_NO UNION ALL SELECT TO_NUMBER(VWI2.CARGO_INFO_ID), VWI2.WEIGH_OUT_DT FROM V_WEIGHT_INFO VWI2 WHERE VWI2.IS_OLD = '是' AND VWI2.PLAN_TYPE IN ('集港', '拆箱集港')) TEMP GROUP BY TEMP.CARGO_INFO_ID) TEMP1 ON TBCI.ROOT_ID = TEMP1.CARGO_INFO_ID JOIN T_BUS_CONTRACT TBC ON (TBC.STATUS = '20' AND TBCC.CONTRACT_ID = TBC.ID AND TCS.CUSTOMER_ID = TBC.CUSTOMER_ID AND
#{date} >= TBC.START_TIME AND #{date} <= TBC.END_TIME
TO_DATE(TO_CHAR(CASE WHEN TBH.LOAD_UNLOAD = '卸' THEN TDS.BERTH_TIME ELSE (CASE when tbh_unLoad.CARGO_INFO_ID is not null then tbh_unLoad.WORK_START_TIME WHEN (TBCI.ROOT_ID IS NULL and tbh_unLoad.CARGO_INFO_ID is null )THEN TEMP.WEIGH_OUT_DT ELSE TBCI.TRANSFER_DATE END) END, 'yyyy-MM-dd'), 'yyyy-MM-dd') >= TBC.START_TIME AND TO_DATE(TO_CHAR(CASE WHEN TBH.LOAD_UNLOAD = '卸' THEN TDS.BERTH_TIME ELSE ( CASE when tbh_unLoad.CARGO_INFO_ID is not null then tbh_unLoad.WORK_START_TIME WHEN (TBCI.ROOT_ID IS NULL and tbh_unLoad.CARGO_INFO_ID is null )THEN TEMP.WEIGH_OUT_DT ELSE TBCI.TRANSFER_DATE END) END, 'yyyy-MM-dd'), 'yyyy-MM-dd') <= TBC.END_TIME
) JOIN T_BUS_CONTRACT_RATE TBCR ON (TBC.ID = TBCR.CONTRACT_ID AND TCS.TRADE_TYPE = TBCR.TRADE_TYPE AND TCS.CARGO_CODE = TBCR.CARGO_CODE) LEFT JOIN T_BUS_TRATE_ITEM TBTI ON (TBCR.TRATE_ITEM_ID = TBTI.ID AND ( TBTI.TRADE_TYPE = '内/外贸' OR TCS.TRADE_TYPE = TBTI.TRADE_TYPE ) AND ( TBTI.IMP_EXP = '进/出口' OR DECODE(TBH.LOAD_UNLOAD, '卸', '进口', '装', '出口') = TBTI.IMP_EXP )) LEFT JOIN T_BUS_TRATE_ITEM_CARGO TBTIC ON (TBTI.ID = TBTIC.TRATE_ITEM_ID AND TBTIC.CARGO_CODE = TBCR.CARGO_CODE) LEFT JOIN T_BUS_TRATE_ITEM_DETAIL TBTID ON TBTI.ID = TBTID.TRATE_ITEM_ID WHERE TCS.ID = #{statementId,jdbcType=BIGINT}

SELECT TBC.ID TBC_ID, TBC.CONTACT_NO TBC_CONTACT_NO, TBC.PARENT_ID TBC_PARENT_ID, TBC.CUSTOMER_ID TBC_CUSTOMER_ID, TBC.CUSTOMER_NAME TBC_CUSTOMER_NAME, TBC.SIGN_TIME TBC_SIGN_TIME, TBC.CONTRACT_TYPE TBC_CONTRACT_TYPE, TBC.IS_SHIP TBC_IS_SHIP, TBC.LUXIAO_SETTLEMENT_BASIS_CODE TBC_SETTLEMENT_BASIS_CODE, TBC.LUXIAO_SETTLEMENT_BASIS_NAME TBC_SETTLEMENT_BASIS_NAME, TBC.OUTER_SETTLEMENT_BASIS_CODE OUTER_SETTLEMENT_BASIS_CODE, TBC.OUTER_SETTLEMENT_BASIS_NAME OUTER_SETTLEMENT_BASIS_NAME, TBC.DEPOSIT_BASIS_CODE TBC_DEPOSIT_BASIS_CODE, TBC.DEPOSIT_BASIS_NAME TBC_DEPOSIT_BASIS_NAME, TBC.DEPOSIT_RATIO TBC_DEPOSIT_RATIO, TBC.PAY_TYPE TBC_PAY_TYPE, TBC.FREE_STORAGE_DAYS TBC_FREE_STORAGE_DAYS, TBC.START_TIME TBC_START_TIME, TBC.END_TIME TBC_END_TIME, TBC.SHIPVOYAGE_ID TBC_SHIPVOYAGE_ID, TBC.VALID_BY TBC_VALID_BY, TBC.VALID_BY_NAME TBC_VALID_BY_NAME, TBC.VALID_TIME TBC_VALID_TIME, TBC.STATUS TBC_STATUS, TBC.REMARK TBC_REMARK, TBC.CREATE_BY TBC_CREATE_BY, TBC.CREATE_BY_NAME TBC_CREATE_BY_NAME, TBC.CREATE_TIME TBC_CREATE_TIME, TBC.UPDATE_BY TBC_UPDATE_BY, TBC.UPDATE_BY_NAME TBC_UPDATE_BY_NAME, TBC.UPDATE_TIME TBC_UPDATE_TIME, TBC.COMPANY_NAMES TBC_COMPANY_NAMES, TBCR.ID TBCR_ID, TBCR.CONTRACT_ID TBCR_CONTRACT_ID, TBCR.CARGO_CODE TBCR_CARGO_CODE, TBCR.CARGO_NAME TBCR_CARGO_NAME, TBCR.RATE_ITEM_CODE TBCR_RATE_ITEM_CODE, TBCR.RATE_ITEM_NAME TBCR_RATE_ITEM_NAME, TBCR.TRADE_TYPE TBCR_TRADE_TYPE, TBCR.SERVICE_CONTENT_ID TBCR_SERVICE_CONTENT_ID, TBCR.SERVICE_CONTENT_NAME TBCR_SERVICE_CONTENT_NAME, TBCR.PAYMENT_TYPE_CODE TBCR_PAYMENT_TYPE_CODE, TBCR.PAYMENT_TYPE_NAME TBCR_PAYMENT_TYPE_NAME, TBCR.PAYMENT_DAYS TBCR_PAYMENT_DAYS, TBCR.RATE TBCR_RATE, TBCR.TAX TBCR_TAX, TBCR.UNIT_CODE TBCR_UNIT_CODE, TBCR.UNIT_NAME TBCR_UNIT_NAME, TBCR.CREATE_BY TBCR_CREATE_BY, TBCR.CREATE_BY_NAME TBCR_CREATE_BY_NAME, TBCR.CREATE_TIME TBCR_CREATE_TIME, TBCR.UPDATE_BY TBCR_UPDATE_BY, TBCR.UPDATE_BY_NAME TBCR_UPDATE_BY_NAME, TBCR.UPDATE_TIME TBCR_UPDATE_TIME, TBTI.ID TBTI_ID, TBTI.TRATE_ID TBTI_TRATE_ID, TBTI.TRADE_TYPE TBTI_TRADE_TYPE, TBTI.IMP_EXP TBTI_IMP_EXP, TBTI.IS_TIERED_RATE TBTI_IS_TIERED_RATE, TBTI.PREFERENTIAL_RATE TBTI_PREFERENTIAL_RATE, TBTI.ORIGIN_ACC_NUMBER TBTI_ORIGIN_ACC_NUMBER, TBTID.ID TBTID_ID, TBTID.TRATE_ITEM_ID TBTID_TRATE_ITEM_ID, TBTID.BEGIN_TON TBTID_BEGIN_TON, TBTID.END_TON TBTID_END_TON, TBTID.RATE TBTID_RATE FROM T_COST_STATEMENT TCS JOIN T_BUS_TRUST TBT ON TBT.ID = TCS.TRUST_ID JOIN T_BUS_CONTRACT_COMPANY TBCC ON TCS.COMPANY_ID = TBCC.COMPANY_ID JOIN T_BUS_HANDOVERLIST TBH ON TCS.HANDOVERLIST_ID = TBH.ID LEFT JOIN T_BUS_CARGO_INFO TBCI ON TBH.CARGO_INFO_ID = TBCI.ID LEFT JOIN (SELECT TEMP.CARGO_INFO_ID, MIN(TEMP.WEIGH_OUT_DT) WEIGH_OUT_DT FROM (SELECT TEMP.CARGO_INFO_ID, VWI.WEIGH_OUT_DT FROM (SELECT TBTC.BUSINESS_NO, TBTC.CARGO_INFO_ID FROM T_BUS_TRUST_CARGO TBTC JOIN T_BUS_TRUST TBT ON TBTC.TRUST_ID = TBT.ID AND TBT.TYPE IN ('集港', '拆箱集港')) TEMP JOIN V_WEIGHT_INFO VWI ON VWI.IS_OLD = '否' AND TEMP.BUSINESS_NO = VWI.PLAN_NO UNION ALL SELECT TO_NUMBER(VWI2.CARGO_INFO_ID), VWI2.WEIGH_OUT_DT FROM V_WEIGHT_INFO VWI2 WHERE VWI2.IS_OLD = '是' AND VWI2.PLAN_TYPE IN ('集港', '拆箱集港')) TEMP GROUP BY TEMP.CARGO_INFO_ID) TEMP ON TBH.CARGO_INFO_ID = TEMP.CARGO_INFO_ID LEFT JOIN (SELECT TEMP.CARGO_INFO_ID, MIN(TEMP.WEIGH_OUT_DT) WEIGH_OUT_DT FROM (SELECT TEMP.CARGO_INFO_ID, VWI.WEIGH_OUT_DT FROM (SELECT TBTC.BUSINESS_NO, TBTC.CARGO_INFO_ID FROM T_BUS_TRUST_CARGO TBTC JOIN T_BUS_TRUST TBT ON TBTC.TRUST_ID = TBT.ID AND TBT.TYPE IN ('集港', '拆箱集港')) TEMP JOIN V_WEIGHT_INFO VWI ON VWI.IS_OLD = '否' AND TEMP.BUSINESS_NO = VWI.PLAN_NO UNION ALL SELECT TO_NUMBER(VWI2.CARGO_INFO_ID), VWI2.WEIGH_OUT_DT FROM V_WEIGHT_INFO VWI2 WHERE VWI2.IS_OLD = '是' AND VWI2.PLAN_TYPE IN ('集港', '拆箱集港')) TEMP GROUP BY TEMP.CARGO_INFO_ID) TEMP1 ON TBCI.ROOT_ID = TEMP1.CARGO_INFO_ID JOIN T_BUS_CONTRACT TBC ON (TBC.STATUS = '20' AND TBCC.CONTRACT_ID = TBC.ID AND TCS.CUSTOMER_ID = TBC.CUSTOMER_ID AND
#{date} >= TBC.START_TIME AND #{date} <= TBC.END_TIME
TO_DATE(TO_CHAR((CASE WHEN TBCI.ROOT_ID IS NULL THEN TEMP.WEIGH_OUT_DT ELSE TBCI.TRANSFER_DATE END), 'yyyy-MM-dd'), 'yyyy-MM-dd') >= TBC.START_TIME AND TO_DATE(TO_CHAR((CASE WHEN TBCI.ROOT_ID IS NULL THEN TEMP.WEIGH_OUT_DT ELSE TBCI.TRANSFER_DATE END), 'yyyy-MM-dd'), 'yyyy-MM-dd') <= TBC.END_TIME
) JOIN T_BUS_CONTRACT_RATE TBCR ON (TBC.ID = TBCR.CONTRACT_ID AND TCS.TRADE_TYPE = TBCR.TRADE_TYPE AND TCS.CARGO_CODE = TBCR.CARGO_CODE) LEFT JOIN T_BUS_TRATE_ITEM TBTI ON (TBCR.TRATE_ITEM_ID = TBTI.ID AND ( TBTI.TRADE_TYPE = '内/外贸' OR TCS.TRADE_TYPE = TBTI.TRADE_TYPE ) AND ( TBTI.IMP_EXP = '进/出口' OR DECODE(TBH.LOAD_UNLOAD, '卸', '进口', '装', '出口') = TBTI.IMP_EXP )) LEFT JOIN T_BUS_TRATE_ITEM_CARGO TBTIC ON (TBTI.ID = TBTIC.TRATE_ITEM_ID AND TBTIC.CARGO_CODE = TBCR.CARGO_CODE) LEFT JOIN T_BUS_TRATE_ITEM_DETAIL TBTID ON TBTI.ID = TBTID.TRATE_ITEM_ID WHERE
TCS.ID = #{statementId,jdbcType=BIGINT}
TCS.ID IN
#{statementId, jdbcType=BIGINT}

