UPDATE T_COST_STATEMENT SET STATUS = #{status, jdbcType=VARCHAR}
, STATEMENT_BY = #{statementBy,jdbcType=BIGINT}, STATEMENT_BY_NAME = #{statementByName,jdbcType=VARCHAR}, STATEMENT_TIME = #{statementTime,jdbcType=TIMESTAMP}
, SETTLEMENT_BASIS_CODE = #{settlementBasisCode,jdbcType=VARCHAR}, SETTLEMENT_BASIS_NAME = #{settlementBasisName,jdbcType=VARCHAR}, STATEMENT_BY = #{statementBy,jdbcType=BIGINT}, STATEMENT_BY_NAME = #{statementByName,jdbcType=VARCHAR}, STATEMENT_TIME = #{statementTime,jdbcType=TIMESTAMP}, REVIEW_BY = #{reviewBy,jdbcType=BIGINT}, REVIEW_BY_NAME = #{reviewByName,jdbcType=VARCHAR}, REVIEW_TIME = #{reviewTime,jdbcType=TIMESTAMP}
, RECEIPT_REMARK = #{receiptRemark,jdbcType=VARCHAR}, TAX_INVOICE_CODE = #{taxInvoiceCode,jdbcType=VARCHAR}, TAX_INVOICE_NAME = #{taxInvoiceName,jdbcType=VARCHAR}, REVIEW_BY = #{reviewBy,jdbcType=BIGINT}, REVIEW_BY_NAME = #{reviewByName,jdbcType=VARCHAR}, REVIEW_TIME = #{reviewTime,jdbcType=TIMESTAMP}, CONFIRM_BY = #{confirmBy,jdbcType=BIGINT}, CONFIRM_BY_NAME = #{confirmByName,jdbcType=VARCHAR}, CONFIRM_TIME = #{confirmTime,jdbcType=TIMESTAMP}
, RECEIPT_REMARK = #{receiptRemark,jdbcType=VARCHAR}, TAX_INVOICE_CODE = #{taxInvoiceCode,jdbcType=VARCHAR}, TAX_INVOICE_NAME = #{taxInvoiceName,jdbcType=VARCHAR}, CONFIRM_BY = #{confirmBy,jdbcType=BIGINT}, CONFIRM_BY_NAME = #{confirmByName,jdbcType=VARCHAR}, CONFIRM_TIME = #{confirmTime,jdbcType=TIMESTAMP}
WHERE ID = #{id, jdbcType=BIGINT}

