SELECT CASE WHEN to_char(TCSD.SERVICE_CONTENT_NAME) IS NULL THEN '包干费' ELSE '包干费' || '(' || to_char(SERVICE_CONTENT_NAME) || ')' END FEE_NAME, TCS.SETTLEMENT_BASIS_NAME, TCS.CARGO_NAME, TBC.CONTACT_NO, TDS.SHIP_NAME || '_' || TDSI.VOYAGE SHIP_NAME_VOYAGE, TCS.STATEMENT_BY_NAME STATEMENT_NAME, TCS.REVIEW_BY_NAME REVIEW_NAME, TCS.CONFIRM_BY_NAME CONFIRM_NAME, TCSD.AMOUNT AMOUNT, TCSD."NUMBER" "number", case when TCS.IS_FINAL != '1' then '本次结算为预结算，完货后进行最终结算，多退少补。' end REMARK, TCSD.RATE RATE FROM T_COST_STATEMENT TCS LEFT JOIN T_COST_STATEMENT_DETAIL TCSD ON TCS.ID = TCSD.STATEMENT LEFT JOIN T_BUS_CONTRACT TBC ON TBC.ID = TCSD.CONTRACT_ID LEFT JOIN T_DIS_SHIPVOYAGE TDS ON TCS.SHIPVOYAGE_ID = TDS.ID LEFT JOIN T_DIS_SHIPVOYAGE_ITEM TDSI ON TCS.SHIPVOYAGE_ITEM_ID = TDSI.ID
TCS.ID IN
#{id}

select TBH.ID FROM T_BUS_HANDOVERLIST TBH LEFT JOIN T_COST_STATEMENT TCS ON TCS.HANDOVERLIST_ID = TBH.ID LEFT JOIN T_COST_STATEMENT_DETAIL TCSD ON TCS.ID = TCSD.STATEMENT where EXISTS ( select * from (
select #{id, jdbcType=BIGINT} as TMPID from dual
) a where a.TMPID = TCS.ID )

select to_char(TEMP.WEIGH_OUT_DT,'yyyy-MM-dd') from T_BUS_CARGO_INFO TBCI join ( SELECT to_char(TBCI3.ID) CARGO_INFO_ID, MIN(TEMP2.WEIGH_OUT_DT) WEIGH_OUT_DT FROM T_BUS_CARGO_INFO TBCI3 JOIN (SELECT to_char(TEMP.CARGO_INFO_ID) CARGO_INFO_ID, VWI.WEIGH_OUT_DT FROM ( SELECT TBTC.BUSINESS_NO, TBTC.CARGO_INFO_ID FROM T_BUS_TRUST_CARGO TBTC JOIN T_BUS_TRUST TBT ON TBTC.TRUST_ID = TBT.ID AND TBT.TYPE IN ('集港', '拆箱集港') ) TEMP JOIN V_WEIGHT_INFO VWI ON VWI.IS_OLD = '否' AND TEMP.BUSINESS_NO = VWI.PLAN_NO
UNION ALL
SELECT to_char(VWI2.CARGO_INFO_ID) CARGO_INFO_ID, VWI2.WEIGH_OUT_DT FROM V_WEIGHT_INFO VWI2 WHERE VWI2.IS_OLD = '是' AND VWI2.PLAN_TYPE IN ('集港', '拆箱集港') ) TEMP2 ON TBCI3.ID = TEMP2.CARGO_INFO_ID group by TBCI3.ID ) TEMP on TEMP.CARGO_INFO_ID = TBCI.ROOT_ID where TBCI.CARGO_INFO_NO = #{cargoInfoNo,jdbcType=VARCHAR}
